// Səyahət planı obyekti
let travelPlan = {
  destination: {
    city: "Paris",
    hotel: {
      name: "Le Grand",
      stars: 5
    }
  },
  flight: {
    airline: "Air France"
  }
};

// Ənənəvi üsul (təhlükəli)
let hotelName = travelPlan.destination && travelPlan.destination.hotel && travelPlan.destination.hotel.name;
console.log(hotelName); // nəticə: "Le Grand"

// Optional Chaining ilə
let safeHotelName = travelPlan.destination?.hotel?.name;
console.log(safeHotelName); // nəticə: "Le Grand"

// Mövcud olmayan xüsusiyyət
let carRental = travelPlan.car?.rentalCompany;
console.log(carRental); // nəticə: undefined (səhv yoxdur!)

// Metod çağırışında istifadə
let hasFlight = travelPlan.flight?.getDetails?.();
console.log(hasFlight); // nəticə: undefined

// Array ilə istifadə
let firstActivity = travelPlan.activities?.[0];
console.log(firstActivity); // nəticə: undefined

// Funksiya parametrində
function getCity(plan) {
  return plan?.destination?.city ?? "Şəhər bilinmir";
}
console.log(getCity(travelPlan)); // nəticə: "Paris"
console.log(getCity({})); // nəticə: "Şəhər bilinmir"

// Səhv gözlənti nümunəsi
let result = travelPlan.destination?.hotel?.stars;
if (result === undefined) {
  console.log("Ulduz sayı bilinmir!"); // nəticə: Ulduz sayı bilinmir! (əgər hotel yoxdursa)
}

// Yanlış istifadə
// travelPlan.destination?.hotel = { name: "New Hotel" }; // Səhv: təyin etmək olmur

// Nullish Coalescing ilə
let hotelStars = travelPlan.destination?.hotel?.stars ?? 3;
console.log(hotelStars); // nəticə: 5 (və ya 3, əgər stars yoxdursa)

