// Travel plan object
let travelPlan = {
  destination: {
    city: "Paris",
    hotel: {
      name: "Le Grand",
      stars: 5
    }
  },
  flight: {
    airline: "Air France"
  }
};

// Traditional way (risky)
let hotelName = travelPlan.destination && travelPlan.destination.hotel && travelPlan.destination.hotel.name;
console.log(hotelName); // Output: "Le Grand"

// With Optional Chaining
let safeHotelName = travelPlan.destination?.hotel?.name;
console.log(safeHotelName); // Output: "Le Grand"

// Accessing non-existent property
let carRental = travelPlan.car?.rentalCompany;
console.log(carRental); // Output: undefined (no error!)

// Using with methods
let hasFlight = travelPlan.flight?.getDetails?.();
console.log(hasFlight); // Output: undefined

// Using with arrays
let firstActivity = travelPlan.activities?.[0];
console.log(firstActivity); // Output: undefined

// In function parameters
function getCity(plan) {
  return plan?.destination?.city ?? "City unknown";
}
console.log(getCity(travelPlan)); // Output: "Paris"
console.log(getCity({})); // Output: "City unknown"

// Misexpectation example
let result = travelPlan.destination?.hotel?.stars;
if (result === undefined) {
  console.log("Star rating unknown!"); // Output: Star rating unknown! (if hotel is missing)
}

// Incorrect usage
// travelPlan.destination?.hotel = { name: "New Hotel" }; // Error: cannot assign

// With Nullish Coalescing
let hotelStars = travelPlan.destination?.hotel?.stars ?? 3;
console.log(hotelStars); // Output: 5 (or 3 if stars is missing)

