// Объект плана путешествия
let travelPlan = {
  destination: {
    city: "Париж",
    hotel: {
      name: "Le Grand",
      stars: 5
    }
  },
  flight: {
    airline: "Air France"
  }
};

// Традиционный способ (рискованный)
let hotelName = travelPlan.destination && travelPlan.destination.hotel && travelPlan.destination.hotel.name;
console.log(hotelName); // Вывод: "Le Grand"

// С опциональной цепочкой
let safeHotelName = travelPlan.destination?.hotel?.name;
console.log(safeHotelName); // Вывод: "Le Grand"

// Доступ к несуществующему свойству
let carRental = travelPlan.car?.rentalCompany;
console.log(carRental); // Вывод: undefined (без ошибки!)

// Использование с методами
let hasFlight = travelPlan.flight?.getDetails?.();
console.log(hasFlight); // Вывод: undefined

// Использование с массивами
let firstActivity = travelPlan.activities?.[0];
console.log(firstActivity); // Вывод: undefined

// В параметрах функции
function getCity(plan) {
  return plan?.destination?.city ?? "Город неизвестен";
}
console.log(getCity(travelPlan)); // Вывод: "Париж"
console.log(getCity({})); // Вывод: "Город неизвестен"

// Пример неправильных ожиданий
let result = travelPlan.destination?.hotel?.stars;
if (result === undefined) {
  console.log("Рейтинг отеля неизвестен!"); // Вывод: Рейтинг отеля неизвестен! (если отель отсутствует)
}

// Неправильное использование
// travelPlan.destination?.hotel = { name: "New Hotel" }; // Ошибка: присваивание невозможно

// С Nullish Coalescing
let hotelStars = travelPlan.destination?.hotel?.stars ?? 3;
console.log(hotelStars); // Вывод: 5 (или 3, если stars отсутствует)

